VALUES
  ('heelevel3-988e0de1-moex-00129', 'heelevel3-988e0de1', 'heelevel3-988e0de1-moex-110-0e802df0', 'sub-heelevel3-988e0de1-01', NULL, 'single_choice', '關於查核人員於審計工作完成階段針對其他資訊之閱讀及考量，下列敘述何者錯誤？', '["公開資訊與財務報表不一致，且錯在公開資訊，當管理階層不願修改時，應視當時情況及 重大不一致情事之性質與嚴重程度，於查核報告中提及該情事，或拒絕出具查核報告、終 止委任合約等", "公開資訊與財務報表不一致，且錯在財務報表，當管理階層不願修改時，應考慮修正意見 為保留意見或無法表示意見", "發現其中有誤述或與報表不一致，應迅速與受查者管理階層研商解決辦法", "查核人員不必承擔「判定其內容是否適當」之責任，亦不必對其是否允當出具報告表示意見"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:26+00:00", "source_pdf_sha1": "64ede6b2988b", "answer_pdf_sha1": "770329449bc6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "326", "s": "1107", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財務審計"}'::jsonb, NULL),
  ('heelevel3-988e0de1-moex-00130', 'heelevel3-988e0de1', 'heelevel3-988e0de1-moex-110-0e802df0', 'sub-heelevel3-988e0de1-01', NULL, 'single_choice', '關於編製財務報表所適用之財務報導架構，如法令對被授權或認可之機構所制定之財務報導 架構另有補充規定，查核人員確認二者間存有衝突。下列作法何者最不適宜？', '["於財務報表中作額外揭露而符合法令規定", "修改財務報表中有關適用之財務報導架構之說明", "依實際查核結果出具查核報告", "不得承接該查核案件"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:26+00:00", "source_pdf_sha1": "64ede6b2988b", "answer_pdf_sha1": "770329449bc6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "326", "s": "1107", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財務審計"}'::jsonb, NULL),
  ('heelevel3-988e0de1-moex-00131', 'heelevel3-988e0de1', 'heelevel3-988e0de1-moex-110-0e802df0', 'sub-heelevel3-988e0de1-01', NULL, 'single_choice', '甲會計師受託查核A公司財務報表，有關現金之盤點，下列敘述何者最為正確？', '["財務報導期間結束日前先作預盤，於報導期間結束日當日再點一次，俾可揭發騰挪（kiting） 狀況", "與有價證券、應收票據等其他易變現資產（negotiableassets）同時進行盤點", "於執行應付帳款截止測試時，同時盤點現金", "收到金融機構詢證回函後立即盤點"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:26+00:00", "source_pdf_sha1": "64ede6b2988b", "answer_pdf_sha1": "770329449bc6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "326", "s": "1107", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財務審計"}'::jsonb, NULL),
  ('heelevel3-988e0de1-moex-00132', 'heelevel3-988e0de1', 'heelevel3-988e0de1-moex-110-0e802df0', 'sub-heelevel3-988e0de1-01', NULL, 'single_choice', '依我國審計準則公報第70號「查核證據─對存貨、訴訟與索賠及營運部門資訊之特別考量」 之規範，如由第三方保管之存貨對財務報表係屬重大，查核人員得執行下列何種程序，俾能', '["閱讀契約、借款合約、租賃合約， 以及與稅捐或其他政府機關之往來文件", "向第三方函證其代為保管存貨之數量及狀況", "檢查其他文件以辨認受查者可能之對外保證", "檢查存貨或執行於當時適當之查核程序"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:26+00:00", "source_pdf_sha1": "64ede6b2988b", "answer_pdf_sha1": "770329449bc6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "326", "s": "1107", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財務審計"}'::jsonb, NULL),
  ('heelevel3-988e0de1-moex-00133', 'heelevel3-988e0de1', 'heelevel3-988e0de1-moex-110-0e802df0', 'sub-heelevel3-988e0de1-01', NULL, 'single_choice', '會計資訊系統處理控制缺乏查核軌跡以供查核團隊查核，執行下列何種查核程序較為適當？', '["執行查詢程序", "觀察人員之職能分工", "複核交易之處理並比較相關輸出值", "複核系統流程制度"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:26+00:00", "source_pdf_sha1": "64ede6b2988b", "answer_pdf_sha1": "770329449bc6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "326", "s": "1107", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財務審計"}'::jsonb, NULL),
  ('heelevel3-988e0de1-moex-00134', 'heelevel3-988e0de1', 'heelevel3-988e0de1-moex-110-0e802df0', 'sub-heelevel3-988e0de1-01', NULL, 'single_choice', '下列有關查核人員對內部稽核工作之採用，何者正確？', '["有效之內部稽核，可減少查核人員之查核程序", "內部稽核已執行固有風險與控制風險之評估，查核人員得逕行參採，毋須再行評估", "會計師於查核報告說明採用內部稽核報告情形，以區分查核責任", "查核人員對內部稽核之適任性及客觀性滿意時，可認定控制風險係屬較低水準"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:26+00:00", "source_pdf_sha1": "64ede6b2988b", "answer_pdf_sha1": "770329449bc6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "326", "s": "1107", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財務審計"}'::jsonb, NULL),
  ('heelevel3-988e0de1-moex-00135', 'heelevel3-988e0de1', 'heelevel3-988e0de1-moex-110-0e802df0', 'sub-heelevel3-988e0de1-01', NULL, 'single_choice', '審計人員發覺各機關長官有財務上不法或不忠於職務上之行為，認為有緊急處分之必要，如 何處理？', '["應立即執行處分", "應立即報告該管審計機關，通知該機關長官從速執行", "應通知其上級機關執行處分", "由審計部呈請監察院核辦"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:26+00:00", "source_pdf_sha1": "64ede6b2988b", "answer_pdf_sha1": "770329449bc6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "326", "s": "1107", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財務審計"}'::jsonb, NULL),
  ('heelevel3-988e0de1-moex-00136', 'heelevel3-988e0de1', 'heelevel3-988e0de1-moex-110-0e802df0', 'sub-heelevel3-988e0de1-01', NULL, 'single_choice', '如受查者係以驗收單作為認列進貨之主要佐證文件，驗收單業已作序號管理與使用，而受查 者年底最後一張驗收單編號為 27321，查核人員在執行進貨之截止測試時，若發現下列那個 驗收單之編號，則表示截止可能錯誤？', '["27320", "27322", "27300", "27321"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:26+00:00", "source_pdf_sha1": "64ede6b2988b", "answer_pdf_sha1": "770329449bc6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "326", "s": "1107", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財務審計"}'::jsonb, NULL),
  ('heelevel3-988e0de1-moex-00137', 'heelevel3-988e0de1', 'heelevel3-988e0de1-moex-110-0e802df0', 'sub-heelevel3-988e0de1-01', NULL, 'single_choice', '下列何者並非合理確信案件之結論？', '["由於否定結論基礎之說明段所述事項之影響重大，依本執業人員之意見，甲公司在所有重 大方面未遵循XX法令", "依本執業人員之意見，甲公司之擬制性資訊在所有重大方面係依照XX基準編製", "依據所執行之程序及所獲取之證據，本執業人員未發現（適當方）就甲公司已遵循XX法 令所作之聲明，在所有重大方面有未允當表達之情事", "依本執業人員之意見，（適當方）就已依照XX基準表達重要績效指標所作之聲明，在所有 重大方面係允當表達"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:26+00:00", "source_pdf_sha1": "64ede6b2988b", "answer_pdf_sha1": "770329449bc6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "326", "s": "1107", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財務審計"}'::jsonb, NULL),
  ('heelevel3-988e0de1-moex-00138', 'heelevel3-988e0de1', 'heelevel3-988e0de1-moex-110-ac2adf20', 'sub-heelevel3-988e0de1-02', NULL, 'essay', '依中央公共債務會計制度規定，其主管機關會計系統是否設有預算控制
